package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint_PathAndCharset_ReturnsCSVPrinter() throws Exception {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        Appendable mockWriter = mock(Appendable.class);

        // Create a subclass of CSVFormat to override print(Path, Charset)
        CSVFormat testFormat = new CSVFormatWrapper(csvFormat, mockWriter, mockPrinter);

        CSVPrinter printer = testFormat.print(mockPath, StandardCharsets.UTF_8);

        assertNotNull(printer);
        assertEquals(mockPrinter, printer);
    }

    @Test
    public void testPrint_PathAndCharset_ThrowsIOException() {
        Path mockPath = mock(Path.class);

        CSVFormat testFormat = new CSVFormatWrapper(csvFormat) {
            @Override
            public CSVPrinter print(Path out, java.nio.charset.Charset charset) throws IOException {
                throw new IOException("IO Error");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> {
            testFormat.print(mockPath, StandardCharsets.UTF_8);
        });

        assertEquals("IO Error", thrown.getMessage());
    }

    // Helper subclass to override print(Path, Charset) without calling private constructor
    private static class CSVFormatWrapper extends CSVFormat {
        private final Appendable mockWriter;
        private final CSVPrinter mockPrinter;

        CSVFormatWrapper(CSVFormat base) {
            super(base);
            this.mockWriter = null;
            this.mockPrinter = null;
        }

        CSVFormatWrapper(CSVFormat base, Appendable mockWriter, CSVPrinter mockPrinter) {
            super(base);
            this.mockWriter = mockWriter;
            this.mockPrinter = mockPrinter;
        }

        @Override
        public CSVPrinter print(Path out, java.nio.charset.Charset charset) throws IOException {
            if (mockWriter != null && mockPrinter != null) {
                return print(mockWriter);
            }
            return super.print(out, charset);
        }
    }
}
